	function _UiComponentSchemaImpl.jsonEncode(self: UiComponentSchema): any
		local output = {}

		if self.kind ~= nil then
			if self.kind.type == "tile" then
				output.tile = self.kind.value:jsonEncode()
			elseif self.kind.type == "game_tile" then
